{"type":"doc","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"E2E-тест на уровне кода — это скрипт, который программно выполняет последовательность действий так, как это сделал бы реальный пользователь в браузере, и затем проверяет, что интерфейс и система в целом выдали ожидаемый результат."}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"В структуре такого теста обычно есть три части:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Подготовка окружения"},{"type":"hardBreak"},{"type":"text","text":"Запуск браузера, переход на нужный URL, подготовка данных или состояния."}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Пошаговая имитация действий пользователя"},{"type":"hardBreak"},{"type":"text","text":"Например: клик по кнопке, ввод текста, выбор элемента, переход по странице."}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Проверка результата (assertions)"},{"type":"hardBreak"},{"type":"text","text":"Проверка, что отображён нужный элемент, изменилось состояние, появился нужный текст, открылась новая страница и т.д."}]}]}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Мини-пример на Playwright (как это выглядит в коде):"}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"test('пользователь может залогиниться', async ({ page }) => {
  await page.goto('https://site.com/login');
  await page.fill('#email', 'test@mail.com');
  await page.fill('#password', '123456');
  await page.click('button[type=submit]');
  await expect(page.getByText('Добро пожаловать')).toBeVisible();
});
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Что видно по примеру:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"тест открывает страницу"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"вводит данные"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"нажимает кнопку"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"проверяет ожидаемый результат"}]}]}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"То есть E2E-тест кодом проходит "},{"type":"text","marks":[{"type":"bold"}],"text":"целый бизнес-сценарий"},{"type":"text","text":", а не отдельную функцию или компонент."}]}]}

{"type":"doc","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Page Object Pattern — это подход в автоматизации UI-тестов, при котором элементы страницы и действия с ними выносятся в отдельный класс (объект страницы). Тест при этом не работает напрямую с селекторами, а вызывает методы этого объекта."}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Зачем он нужен:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"изолирует селекторы в одном месте"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"уменьшает дублирование кода"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"упрощает поддержку тестов при изменениях в верстке"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"делает тесты более читабельными"}]}]}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Структура:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Класс страницы (Page Object)"},{"type":"text","text":" — содержит селекторы и методы: "},{"type":"text","marks":[{"type":"code"}],"text":"loginPage.login(email, pass)"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"code"}],"text":"loginPage.submit()"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Тест"},{"type":"text","text":" — вызывает только методы страницы, без знаний о деталях DOM"}]}]}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Схематично:"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"italic"}],"text":"Page Object"}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"class LoginPage {
  constructor(page) {
    this.page = page;
    this.emailInput = '#email';
    this.passwordInput = '#password';
    this.submitButton = '#submit';
  }

  async login(email, password) {
    await this.page.fill(this.emailInput, email);
    await this.page.fill(this.passwordInput, password);
    await this.page.click(this.submitButton);
  }
}
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"italic"}],"text":"Тест"}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"test('логин работает', async ({ page }) => {
  const loginPage = new LoginPage(page);

  await page.goto('/login');
  await loginPage.login('user@mail.com', '123456');

  await expect(page.getByText('Добро пожаловать')).toBeVisible();
});
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Суть в одном предложении:"},{"type":"text","text":" Page Object Pattern — это слой-обёртка над страницей, чтобы тесты оперировали бизнес-действиями, а не DOM-локаторами."}]}]}
